import{_ as a,o as l,c as i,a3 as t}from"./chunks/framework.BTFg6ESq.js";const m=JSON.parse('{"title":"虚拟时间线 (Virtual Timeline)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/agents/virtual-timeline.md","filePath":"user-guide/tools/llm-chat/agents/virtual-timeline.md","lastUpdated":1778244893000}'),r={name:"user-guide/tools/llm-chat/agents/virtual-timeline.md"};function o(n,e,s,d,c,h){return l(),i("div",null,[...e[0]||(e[0]=[t('<div><h1 id="虚拟时间线-virtual-timeline" tabindex="-1">虚拟时间线 (Virtual Timeline) <a class="header-anchor" href="#虚拟时间线-virtual-timeline" aria-label="Permalink to &quot;虚拟时间线 (Virtual Timeline)&quot;">​</a></h1><p>虚拟时间线是为角色扮演（Roleplay）场景设计的核心功能，允许你为 Agent 设定一个独立于现实世界的“游戏时间”。</p><h2 id="_1-核心概念" tabindex="-1">1. 核心概念 <a class="header-anchor" href="#_1-核心概念" aria-label="Permalink to &quot;1. 核心概念&quot;">​</a></h2><p>通过虚拟时间线，你可以让 Agent 意识到当前处于虚拟世界的哪个时刻，从而在对话中表现出符合时间背景的行为（如：深夜时的困倦、特定节日的庆祝）。</p><ul><li><strong>虚拟基准点</strong>: 虚拟世界的起始时间（如：2077年10月23日 09:00）。</li><li><strong>现实基准点</strong>: 对应现实世界的时刻。系统支持一键同步为“当前现实时间”。</li><li><strong>时间流速倍率</strong>: 虚拟时间相对于现实时间的流逝速度。 <ul><li><code>1.0</code>: 虚拟时间与现实同步。</li><li><code>2.0</code>: 现实过去 1 小时，虚拟世界过去 2 小时。</li><li><code>0.0</code>: 虚拟时间静止。</li></ul></li></ul><h2 id="_2-宏系统联动" tabindex="-1">2. 宏系统联动 <a class="header-anchor" href="#_2-宏系统联动" aria-label="Permalink to &quot;2. 宏系统联动&quot;">​</a></h2><p>虚拟时间线最强大的地方在于它与<a href="./../macro-system/index">宏系统</a>的深度集成。你可以直接在系统提示词或预设消息中使用以下宏：</p><ul><li><code>{{time}}</code>: 虚拟世界的当前时间（24小时制）。</li><li><code>{{datetime_cn}}</code>: 虚拟世界的中文完整日期时间。</li><li><code>{{shichen}}</code>: 虚拟时刻对应的中国传统时辰（如：子时、寅时）。</li><li><code>{{virtual_day_progress}}</code>: 当前虚拟天内的进度百分比。</li></ul><h2 id="_3-实时预览" tabindex="-1">3. 实时预览 <a class="header-anchor" href="#_3-实时预览" aria-label="Permalink to &quot;3. 实时预览&quot;">​</a></h2><p>在 Agent 编辑器的虚拟时间线面板中，提供了一个<strong>实时预览区域</strong>：</p><ul><li>你可以输入任何包含时间宏的文本。</li><li>系统会每秒自动刷新预览结果，让你直观看到在当前流速下，宏是如何展开的。</li></ul><h2 id="_4-使用场景示例" tabindex="-1">4. 使用场景示例 <a class="header-anchor" href="#_4-使用场景示例" aria-label="Permalink to &quot;4. 使用场景示例&quot;">​</a></h2><h3 id="场景-a-异世界冒险" tabindex="-1">场景 A：异世界冒险 <a class="header-anchor" href="#场景-a-异世界冒险" aria-label="Permalink to &quot;场景 A：异世界冒险&quot;">​</a></h3><ul><li><strong>设定</strong>: 虚拟基准点设为“1202年”，流速设为 <code>3.0</code>（快节奏冒险）。</li><li><strong>提示词</strong>: <code>当前时间是 {{datetime_cn}}，你正处于 {{shichen}}。</code></li><li><strong>效果</strong>: 随着现实时间的推移，Agent 会自动感知到虚拟世界天色的变化，并在回复中提及“夜深了”或“正午阳光刺眼”。</li></ul><h3 id="场景-b-历史模拟" tabindex="-1">场景 B：历史模拟 <a class="header-anchor" href="#场景-b-历史模拟" aria-label="Permalink to &quot;场景 B：历史模拟&quot;">​</a></h3><ul><li><strong>设定</strong>: 虚拟基准点设为“1945年”，流速设为 <code>0.0</code>。</li><li><strong>效果</strong>: 无论现实过去多久，Agent 始终认为自己处于那个特定的历史时刻。</li></ul><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./../macro-system/macro-reference">宏系统参考</a></li><li><a href="./editor-guide">Agent 基础设定</a></li></ul></div>',1)])])}const g=a(r,[["render",o]]);export{m as __pageData,g as default};
